use crate::middleware::{Middleware, Request, Response};
use dashmap::DashMap;
use std::future::Future;
use std::pin::Pin;
use std::sync::Arc;
use std::time::Instant;

struct TokenBucket {
    tokens: f64,
    last_refill: Instant,
    max_tokens: f64,
    refill_rate: f64,
}

impl TokenBucket {
    fn new(max_tokens: f64, refill_rate: f64) -> Self {
        Self {
            tokens: max_tokens,
            last_refill: Instant::now(),
            max_tokens,
            refill_rate,
        }
    }

    fn try_consume(&mut self) -> bool {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill).as_secs_f64();
        self.tokens = (self.tokens + elapsed * self.refill_rate).min(self.max_tokens);
        self.last_refill = now;

        if self.tokens >= 1.0 {
            self.tokens -= 1.0;
            true
        } else {
            false
        }
    }
}

pub struct RateLimiter {
    buckets: Arc<DashMap<String, TokenBucket>>,
    max_requests: f64,
    refill_rate: f64,
}

impl RateLimiter {
    pub fn new(max_requests_per_window: u32, window_secs: u64) -> Self {
        let max_requests = max_requests_per_window as f64;
        let refill_rate = max_requests / window_secs as f64;
        Self {
            buckets: Arc::new(DashMap::new()),
            max_requests,
            refill_rate,
        }
    }
}

impl Middleware for RateLimiter {
    fn handle(&self, req: Request) -> Pin<Box<dyn Future<Output = Response> + Send>> {
        let buckets = self.buckets.clone();
        let max = self.max_requests;
        let rate = self.refill_rate;

        Box::pin(async move {
            let ip = req.remote_addr().to_string();
            let mut bucket = buckets
                .entry(ip)
                .or_insert_with(|| TokenBucket::new(max, rate));

            if bucket.try_consume() {
                req.next().await
            } else {
                Response::too_many_requests("Rate limit exceeded. Try again later.")
            }
        })
    }
}

