    let (shutdown_tx, shutdown_rx) = watch::channel(false);

    let server = tokio::spawn({
        let mut shutdown_rx = shutdown_rx.clone();
        async move {
            loop {
                tokio::select! {
                    _ = accept_connection() => {}
